using System.Text.Json;
using System.Text.Json.Serialization.Metadata;

var options = new JsonSerializerOptions
{
    TypeInfoResolver = new DefaultJsonTypeInfoResolver()
};

// 1) Strongly-typed retrieval: GetTypeInfo<T>() returns JsonTypeInfo<T> directly.
JsonTypeInfo<Person> personInfo = options.GetTypeInfo<Person>();
Console.WriteLine($"Got typed metadata for Person: {personInfo.Type.Name}");

// 2) Probe without throwing: TryGetTypeInfo returns false instead of throwing.
bool hasPerson = options.TryGetTypeInfo(typeof(Person), out JsonTypeInfo? info);
Console.WriteLine($"TryGetTypeInfo(Person) => found={hasPerson}, info={info?.Type.Name}");

// Try a type that has no resolver configured (use a fresh options with NO resolver).
var empty = new JsonSerializerOptions();
bool hasWidget = empty.TryGetTypeInfo(typeof(Widget), out JsonTypeInfo? widgetInfo);
Console.WriteLine($"TryGetTypeInfo(Widget) on empty resolver => found={hasWidget}, info={widgetInfo?.Type.Name ?? "null"}");

record Person(string Name, int Age);
record Widget(int Id);

